document.getElementById('summaryCards').innerHTML = items.map(item => {
    const val = curr[item.k];
    const cval = comp ? comp[item.k] : null;
    const change = pct(val, cval);
    return `<div class="summary-card">
        <div class="card-label">${item.label}</div>
        <div class="card-value">${fmt(val)}</div>
        ${change !== null ? `<div class="card-change ${changeClass(change)}">${arrow(change)} ${Math.abs(change)}% ${comp ? 'vs ' + comp.label : ''}</div>` : '<div class="card-change neutral">—</div>'}
    </div>`;
}).join('');

