document.getElementById('summaryCards').innerHTML = items.map(item => {
    const v = curr[item.k];
    const cv = comp ? comp[item.k] : null;
    const ch = pct(v, cv);
    const l = item.label;
    if(ch!==null){const delta=v-cv;const sign=delta>=0?'+':'';return `<div class="summary-card"><div class="card-label">${l}</div><div class="card-value">${fmt(v)}</div><div class="card-change ${changeClass(ch)}">${arrow(ch)} ${sign}${fmt(delta)} (${Math.abs(ch)}%)</div><div class="card-compare">${fmt(cv)} → ${fmt(v)} · vs ${comp.label}</div></div>`;}
    return `<div class="summary-card"><div class="card-label">${l}</div><div class="card-value">${fmt(v)}</div><div class="card-change neutral">—</div></div>`;
}).join('');

